def _execute_ast(node):
    if isinstance(node, ast.Num):  # Check for numeric values (constants).
        return node.n
    elif isinstance(node, ast.Str):  # Check for string literals.
        return str(node.s)
    elif isinstance(node, (ast.BinOp, ast.UnaryOp)):  # Perform arithmetic operations if possible.
        left = _execute_ast(node.left)
        right = _execute_ast(node.right)

